questionvariables.text:
/* 1. Define Rotation Parameters */
/* Centre O is fixed at [1, 1] for this randomization */
/* Randomize centre between -2 and 2 on both axes */
cx: -2 + rand(5); 
cy: -2 + rand(5); 
/* 2. Define Original Triangle ABC */
x1: -4; y1: 2;
x2: -6; y2: 4;
x3: -7; y3: 1;
pA: [x1, y1]; pB: [x2, y2]; pC: [x3, y3];

/* 3. Rotation (90 degrees clockwise / -90 degrees) */
/* Rule: (x,y) -> (y-cy+cx, -(x-cx)+cy) */
rotate_pt(p) := [p[2]-cy+cx, -(p[1]-cx)+cy];

pA_prime: rotate_pt(pA);
pB_prime: rotate_pt(pB);
pC_prime: rotate_pt(pC);

/* 4. Teacher Answers */
ta1: [cx, cy];
ta2: -90; /* Clockwise */
